INSERT INTO `Product` (`id`, `name`, `slug`, `description`, `price`, `imageUrl`, `images`, `stock`, `category`, `createdAt`, `updatedAt`) VALUES
('3e59de7b-d1bc-4ee1-82da-78b7182930ee', '24K Gold Serum', '24k-gold-serum', 'Using a 24K gold face serum or cream can help you achieve that tight, radiant complexion. 24K gold has natural anti-inflammatory properties, making it ideal for soothing irritated or sensitive skin.', 2499.00, '/uploads/1773860452397-24kgoldserum.jpg', '["/uploads/1773860452407-01.jpg","/uploads/1773860452408-02.jpg"]', 47, 'Serums', '2026-03-18 19:00:52.419', '2026-03-21 17:00:34.636'),
('409b2297-c76e-420b-ae38-def6fd30018d', 'Scene Cinematic 4k', 'scene-cinematic-4k', 'A sweeping cinematic 4K scene unfolds at golden hour, where light dances across vast landscapes, shadows deepen, and every detail feels vivid, immersive, and breathtakingly real.', 2499.00, '/uploads/1774286255668-scenecinematic4k202602112351.jpeg', '["/uploads/1774286269555-scenepremium4k202602112234.jpeg","/uploads/1774286269559-scenesun4k202602112354.jpeg"]', 50, 'Serums', '2026-03-23 17:17:07.481', '2026-03-23 17:17:49.567'),
('5e208600-b7b1-4311-98d4-b656f2d22ff3', 'Bold Cinematic Hero 4k', 'bold-cinematic-hero-4k', 'A bold cinematic 4K hero stands against a dramatic backdrop, wind rushing past as light cuts through shadows, capturing power, intensity, and epic larger-than-life presence.', 2499.00, '/uploads/1774286574411-Lemonfacewashbottle4k2026011913252.jpeg', '["/uploads/1774286588654-Hyperrealisticlemonfacewash4k202601191321.jpeg","/uploads/1774287062467-Lemonfacewashbottle4k2026011913252.jpeg"]', 50, 'Serums', '2026-03-23 17:22:54.416', '2026-03-23 17:31:02.477'),
('656b6349-7c2d-4ee4-b9ed-a81342c02e17', 'Ultraluxury Skincare Editorial 4k', 'ultraluxury-skincare-editorial-4k', 'An ultra-luxury skincare editorial in 4K showcases radiant skin, glossy textures, and opulent lighting, blending elegance, precision, and high-fashion sophistication.', 2499.00, '/uploads/1774286782880-Ultraluxuryskincareproduct4k2026020221201.jpeg', '["/uploads/1774286793484-Ultraluxuryskincareeditorial4k20260202221.jpeg","/uploads/1774287048951-Ultraluxuryskincareproduct4k2026020221201.jpeg"]', 50, 'Serums', '2026-03-23 17:26:22.886', '2026-03-23 17:30:48.958');
